/* str.h -- String and memory utilities for PL/SW compiler on COR24 */
/* Freestanding -- no libc */

#ifndef STR_H
#define STR_H

int str_len(char *s) {
    int n = 0;
    while (*s) {
        n = n + 1;
        s = s + 1;
    }
    return n;
}

void str_copy(char *dst, char *src) {
    while (*src) {
        *dst = *src;
        dst = dst + 1;
        src = src + 1;
    }
    *dst = 0;
}

/* Copy up to max-1 chars, always null-terminate */
void str_ncopy(char *dst, char *src, int max) {
    int i = 0;
    while (*src && i < max - 1) {
        *dst = *src;
        dst = dst + 1;
        src = src + 1;
        i = i + 1;
    }
    *dst = 0;
}

/* Returns 0 if equal, <0 if a<b, >0 if a>b */
int str_cmp(char *a, char *b) {
    while (*a && *b && *a == *b) {
        a = a + 1;
        b = b + 1;
    }
    return *a - *b;
}

/* Returns 1 if equal, 0 otherwise */
int str_eq(char *a, char *b) {
    while (*a && *b && *a == *b) {
        a = a + 1;
        b = b + 1;
    }
    return *a == *b;
}

void mem_set(char *dst, int val, int n) {
    while (n > 0) {
        *dst = val;
        dst = dst + 1;
        n = n - 1;
    }
}

void mem_copy(char *dst, char *src, int n) {
    while (n > 0) {
        *dst = *src;
        dst = dst + 1;
        src = src + 1;
        n = n - 1;
    }
}

#endif

/* arena.h -- Bump allocator for PL/SW compiler tables on COR24 */
/* Freestanding -- no libc, no malloc */

#ifndef ARENA_H
#define ARENA_H

#include "str.h"

/* Arena size in bytes -- 16KB for compiler tables */
#define ARENA_SIZE 16384

char arena_buf[ARENA_SIZE];
int arena_top;

void arena_init(void) {
    arena_top = 0;
}

/* Allocate n bytes from the arena. Returns pointer or 0 on OOM. */
char *arena_alloc(int n) {
    if (arena_top + n > ARENA_SIZE) {
        return 0;
    }
    char *p = arena_buf + arena_top;
    arena_top = arena_top + n;
    /* Zero-fill the allocation */
    mem_set(p, 0, n);
    return p;
}

/* Return current watermark (for save/restore) */
int arena_save(void) {
    return arena_top;
}

/* Restore arena to a saved watermark */
void arena_restore(int mark) {
    arena_top = mark;
}

/* How many bytes remain */
int arena_free(void) {
    return ARENA_SIZE - arena_top;
}

#endif

